"use client";
import * as React from "react";
import { skeletonAnatomy } from "@tessera/core";

export interface SkeletonProps extends React.HTMLAttributes<HTMLDivElement> {
  variant?: "rect" | "text" | "circle";
  width?: number | string;
  height?: number | string;
}

export const Skeleton = React.forwardRef<HTMLDivElement, SkeletonProps>(function Skeleton(
  { variant = "rect", width, height, style, ...rest },
  ref
) {
  return (
    <div
      {...skeletonAnatomy.attrs("root")}
      data-variant={variant}
      aria-hidden
      style={{ width, height, ...style }}
      ref={ref}
      {...rest}
    />
  );
});

@layer tessera.recipes {
  [data-scope="skeleton"][data-part="root"] {
    display: block;
    background: var(--ts-bg-muted);
    border-radius: var(--ts-radius-md);
    animation: tessera-pulse 1.6s var(--ts-easing-standard) infinite;
  }

  [data-scope="skeleton"][data-part="root"][data-variant="text"] {
    height: 0.9em;
    border-radius: var(--ts-radius-sm);
  }

  [data-scope="skeleton"][data-part="root"][data-variant="circle"] {
    border-radius: var(--ts-radius-full);
  }

  @keyframes tessera-pulse {
    0%,
    100% {
      opacity: 1;
    }
    50% {
      opacity: 0.45;
    }
  }

  @media (prefers-reduced-motion: reduce) {
    [data-scope="skeleton"][data-part="root"] {
      animation: none;
    }
  }
}
